prontera,150,150,4    script    Hello NPC    100,{

    mes "[Hello NPC]";
    mes "請問你想選擇哪一種藥水？";
    next;

    // 顯示選單，選項依序為第一個、第二個...
    switch(select("藍色藥水（恢復 SP 100）:紅色藥水（恢復 HP 100）")) {
        case 1:
            mes "[Hello NPC]";
            mes "你選擇了藍色藥水！";
            getitem 504,1; // 504 是藍色藥水的道具 ID
            close;
        case 2:
            mes "[Hello NPC]";
            mes "你選擇了紅色藥水！";
            getitem 501,1; // 501 是紅色藥水的道具 ID
            close;
    }
}

